import { Component, OnInit, Output, EventEmitter } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-sidebar',
  templateUrl: './sidebar.component.html',
  styleUrls: ['./sidebar.component.css']
})
export class SidebarComponent implements OnInit {
  @Output() toggleSidebar = new EventEmitter<void>();

  userRole: string = '';
  userName: string = '';
  userEmail: string = '';
  menuItems: any[] = [];
  isCollapsed = false;

  constructor(
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit() {
    this.userRole = this.authService.getCurrentUserRole();
    this.loadMenuItems();

    const user = JSON.parse(localStorage.getItem('currentUser') || '{}');
    this.userName = user.fullName || user.username || 'User';
    this.userEmail = user.email || 'user@example.com';
  }

  loadMenuItems() {
    switch(this.userRole) {
      case 'Requestor':
        this.menuItems = [
          { icon: 'fas fa-tachometer-alt', label: 'Dashboard', route: '/requestor/dashboard', active: false },
          { icon: 'fas fa-plus-circle', label: 'Create Request', route: '/requestor/create', active: false },
          { icon: 'fas fa-list-alt', label: 'My Requests', route: '/requestor/my-requests', active: false }
        ];
        break;

      case 'Manager':
        this.menuItems = [
          { icon: 'fas fa-tachometer-alt', label: 'Dashboard', route: '/manager/dashboard', active: false },
          { icon: 'fas fa-clock', label: 'Pending Approvals', route: '/manager/pending', active: false }
        ];
        break;

      case 'FinanceAdmin':
        this.menuItems = [
          { icon: 'fas fa-tachometer-alt', label: 'Dashboard', route: '/finance/dashboard', active: false },
          { icon: 'fas fa-money-bill-wave', label: 'Finance Review', route: '/finance/review', active: false }
        ];
        break;

      case 'SystemAdmin':
        this.menuItems = [
          { icon: 'fas fa-tachometer-alt', label: 'Dashboard', route: '/admin/dashboard', active: false },
          { icon: 'fas fa-tasks', label: 'All Requests', route: '/admin/all-requests', active: false },
          { icon: 'fas fa-tags', label: 'Manage Types', route: '/admin/manage-types', active: false }
        ];
        break;

      default:
        this.menuItems = [];
    }
  }

  onToggle() {
    this.isCollapsed = !this.isCollapsed;
    this.toggleSidebar.emit();
  }

  setActive(menuItem: any) {
    this.menuItems.forEach(item => item.active = false);
    menuItem.active = true;
  }

  logout() {
    this.authService.logout();
    this.router.navigate(['/auth/login']);
  }

  getUserInitials(): string {
    const names = this.userName.split(' ');
    if (names.length >= 2) {
      return (names[0][0] + names[1][0]).toUpperCase();
    }
    return this.userName.substring(0, 2).toUpperCase();
  }
}
<div class="sidebar" [class.collapsed]="isCollapsed">
  <!-- Toggle Button -->
  <button class="sidebar-toggle" (click)="onToggle()">
    <i [class]="isCollapsed ? 'fas fa-chevron-right' : 'fas fa-chevron-left'"></i>
  </button>

  <!-- Logo -->
  <div class="sidebar-logo">
    <i class="fas fa-handshake"></i>
    <span *ngIf="!isCollapsed">Sponsorship<br>Workflow</span>
  </div>

  <!-- User Profile -->
  <div class="user-profile">
    <div class="avatar">
      <div class="avatar-circle">
        <span class="avatar-initials">{{ getUserInitials() }}</span>
      </div>
    </div>
    <div class="user-info" *ngIf="!isCollapsed">
      <h5 class="user-name">{{ userName }}</h5>
      <span class="user-role">{{ userRole }}</span>
    </div>
  </div>

  <!-- Navigation Menu -->
  <nav class="sidebar-nav">
    <ul class="nav-menu">
      <li *ngFor="let item of menuItems" class="nav-item">
        <a [routerLink]="item.route"
           class="nav-link"
           [class.active]="item.active"
           (click)="setActive(item)">
          <i [class]="item.icon"></i>
          <span *ngIf="!isCollapsed">{{ item.label }}</span>
        </a>
      </li>
    </ul>
  </nav>

  <!-- Footer -->
  <div class="sidebar-footer">
    <button class="logout-btn" (click)="logout()">
      <i class="fas fa-sign-out-alt"></i>
      <span *ngIf="!isCollapsed">Logout</span>
    </button>
  </div>
</div>
